-- ============================================================
-- OrientTN — Base de données complète 2025
-- Source : Dليل طاقة استيعاب — دورة التوجيه الجامعي 2025
-- Score sur 210 points (somme pondérée des notes du bac)
-- 689 filières · 10 domaines · Toutes universités tunisiennes
-- ============================================================

SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

-- ────────────────────────────────────────────
-- TABLES
-- ────────────────────────────────────────────

DROP TABLE IF EXISTS candidatures;
DROP TABLE IF EXISTS filieres;
DROP TABLE IF EXISTS universites;
DROP TABLE IF EXISTS gouvernorats;
DROP TABLE IF EXISTS utilisateurs;
DROP TABLE IF EXISTS bac_sections;

CREATE TABLE gouvernorats (
    id          INT PRIMARY KEY AUTO_INCREMENT,
    nom         VARCHAR(60)  NOT NULL,
    region      VARCHAR(60)  NOT NULL,
    created_at  DATETIME DEFAULT NOW()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE universites (
    id              INT PRIMARY KEY AUTO_INCREMENT,
    nom             VARCHAR(200) NOT NULL,
    sigle           VARCHAR(60),
    gouvernorat_id  INT,
    type            ENUM('publique','privée') DEFAULT 'publique',
    site_web        VARCHAR(200),
    created_at      DATETIME DEFAULT NOW(),
    FOREIGN KEY (gouvernorat_id) REFERENCES gouvernorats(id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE bac_sections (
    id          INT PRIMARY KEY AUTO_INCREMENT,
    code        VARCHAR(10) NOT NULL UNIQUE,
    nom_ar      VARCHAR(100),
    nom_fr      VARCHAR(100) NOT NULL,
    description VARCHAR(300)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE filieres (
    id              INT PRIMARY KEY AUTO_INCREMENT,
    code_orientation VARCHAR(10) NOT NULL UNIQUE COMMENT 'Code 5 chiffres du guide officiel',
    titre           VARCHAR(200) NOT NULL,
    domaine         VARCHAR(100) NOT NULL,
    type_formation  VARCHAR(100),
    description     TEXT,
    description_longue TEXT,
    debouches       JSON,
    matieres        JSON,
    universite_id   INT,
    score_min       DECIMAL(6,2) NOT NULL COMMENT 'Score min sur 210',
    score_moyen     DECIMAL(6,2),
    score_max       DECIMAL(6,2),
    capacite        INT,
    duree           TINYINT DEFAULT 3,
    langue          VARCHAR(60),
    formule_calcul  VARCHAR(100) COMMENT 'Formule de calcul du score (ex: FG+M)',
    bac_requis      VARCHAR(200) COMMENT 'Sections du bac acceptées',
    icon            VARCHAR(10),
    couleur_classe  VARCHAR(20) DEFAULT 'ct-def',
    statut          ENUM('active','inactive') DEFAULT 'active',
    created_at      DATETIME DEFAULT NOW(),
    updated_at      DATETIME DEFAULT NOW() ON UPDATE NOW(),
    FOREIGN KEY (universite_id) REFERENCES universites(id),
    INDEX idx_score    (score_min),
    INDEX idx_domaine  (domaine),
    INDEX idx_statut   (statut)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE utilisateurs (
    id              INT PRIMARY KEY AUTO_INCREMENT,
    prenom          VARCHAR(60) NOT NULL,
    nom             VARCHAR(60) NOT NULL,
    email           VARCHAR(150) NOT NULL UNIQUE,
    mot_de_passe    VARCHAR(255) NOT NULL,
    serie           VARCHAR(60),
    score_bac       DECIMAL(6,2) COMMENT 'Score sur 210',
    gouvernorat     VARCHAR(60),
    role            ENUM('etudiant','admin') DEFAULT 'etudiant',
    created_at      DATETIME DEFAULT NOW()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE candidatures (
    id              INT PRIMARY KEY AUTO_INCREMENT,
    utilisateur_id  INT NOT NULL,
    filiere_id      INT NOT NULL,
    created_at      DATETIME DEFAULT NOW(),
    UNIQUE KEY uq_cand (utilisateur_id, filiere_id),
    FOREIGN KEY (utilisateur_id) REFERENCES utilisateurs(id) ON DELETE CASCADE,
    FOREIGN KEY (filiere_id)     REFERENCES filieres(id)     ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

